(function () {
if (window.__thon09GisSearchLoaded) return;
window.__thon09GisSearchLoaded = true;
const API = '/api/gis/search';
const state = {
timer: null,
results: [],
marker: null,
polygonHighlight: null,
};
function qs(selector, root = document) {
return root.querySelector(selector);
}
function showToast(message, type = 'info') {
if (typeof window.toast === 'function') {
window.toast(message, type);
} else if (typeof window.showToast === 'function') {
window.showToast(message, type);
} else {
console[type === 'error' ? 'error' : 'log'](message);
}
}
function authHeaders() {
const headers = { Accept: 'application/json' };
const token = document.querySelector('meta[name="csrf-token"]')?.getAttribute('content')
|| window.csrfToken
|| window.CSRF_TOKEN
|| '';
if (token) headers['X-CSRF-TOKEN'] = token;
if (window.App && window.App.token) headers.Authorization = 'Bearer ' + window.App.token;
return headers;
}
function mapInstance() {
return window.App?.gis?.map || window.gisMap || null;
}
function isAuthenticated() { return Boolean(window.App && window.App.token); }
function areaList() {
const areas = window.App?.gis?.areas;
return Array.isArray(areas) ? areas : [];
}
function escapeHtml(value) {
return String(value ?? '').replace(/[&<>'"]/g, (char) => ({
'&': '&amp;',
'<': '&lt;',
'>': '&gt;',
"'": '&#39;',
'"': '&quot;',
}[char]));
}
function buildPopup(item) {
return `
<div class="gis-household-popup">
<strong>${escapeHtml(item.household_code || '')}</strong><br>
<span>${escapeHtml(item.head_name || 'Chưa có chủ hộ')}</span><br>
<small>${escapeHtml(item.address || '')}</small><br>
<div class="mt-1">${Number(item.total_members || 0)} nhân khẩu</div>
<div class="mt-1"><span class="badge bg-success-subtle text-success-emphasis">${escapeHtml(item.household_type || 'Không ưu tiên')}</span></div>
</div>
`;
}
function blinkElement(element) {
if (!element) return;
element.classList.add('gis-search-blink');
window.setTimeout(() => element.classList.remove('gis-search-blink'), 3000);
}
function highlightArea(areaCode) {
const map = mapInstance();
if (!map || !window.L || !areaCode) return;
const area = areaList().find((item) => String(item.area_code || '') === String(areaCode));
if (!area || !area.polygon || !Array.isArray(area.polygon.coordinates)) return;
if (state.polygonHighlight) {
map.removeLayer(state.polygonHighlight);
state.polygonHighlight = null;
}
try {
const coordinates = area.polygon.type === 'Polygon' ? area.polygon.coordinates[0] : area.polygon.coordinates;
const latLngs = coordinates.map((point) => [Number(point[1]), Number(point[0])]);
state.polygonHighlight = window.L.polygon(latLngs, {
color: '#f59e0b',
weight: 4,
opacity: 0.9,
fillColor: '#fef3c7',
fillOpacity: 0.28,
interactive: false,
}).addTo(map);
window.setTimeout(() => {
if (state.polygonHighlight) {
map.removeLayer(state.polygonHighlight);
state.polygonHighlight = null;
}
}, 3500);
} catch (error) {
console.warn('[GIS Search] Không highlight được polygon', error);
}
}
function focusHousehold(item) {
const map = mapInstance();
if (!map || !window.L) {
showToast('Bản đồ chưa sẵn sàng.', 'warning');
return;
}
if (!item.has_location || item.latitude === null || item.longitude === null) {
showToast('Hộ này chưa có tọa độ trên bản đồ.', 'warning');
return;
}
const latLng = [Number(item.latitude), Number(item.longitude)];
const focused = typeof window.thon09GisFocusHouseholdMarker === 'function'
? window.thon09GisFocusHouseholdMarker(item)
: false;
if (!focused) {
if (state.marker) map.removeLayer(state.marker);
state.marker = window.L.marker(latLng).addTo(map).bindPopup(buildPopup(item));
map.setView(latLng, Math.max(map.getZoom(), 17), { animate: true });
state.marker.openPopup();
blinkElement(state.marker.getElement && state.marker.getElement());
}
highlightArea(item.area_code);
}
async function search(query) {
if (!isAuthenticated()) return [];
const url = `${API}?q=${encodeURIComponent(query)}`;
const response = await fetch(url, { headers: authHeaders(), credentials: 'same-origin' });
const json = await response.json().catch(() => null);
if (response.status === 401) {
if (typeof window.clearClientSession === 'function') window.clearClientSession();
if (typeof window.showLogin === 'function') window.showLogin();
return [];
}
if (!response.ok || !json) {
throw new Error(json?.error?.message || json?.message || 'Không tìm kiếm được GIS');
}
return json.data?.items || json.items || [];
}
function renderResults(box, items) {
const list = qs('.gis-search-results', box);
if (!list) return;
state.results = items.slice(0, 10);
if (state.results.length === 0) {
list.innerHTML = '<div class="gis-search-empty">Không tìm thấy hộ phù hợp</div>';
list.hidden = false;
return;
}
list.innerHTML = state.results.map((item, index) => `
<button type="button" class="gis-search-item" data-index="${index}">
<span class="gis-search-code">${escapeHtml(item.household_code)}</span>
<span class="gis-search-name">${escapeHtml(item.head_name || 'Chưa có chủ hộ')}</span>
<span class="gis-search-meta">${escapeHtml(item.address || '')}</span>
${item.has_location ? '' : '<span class="gis-search-warning">Chưa định vị</span>'}
</button>
`).join('');
list.hidden = false;
}
function ensureStyles() {
if (document.getElementById('gis-search-style')) return;
const style = document.createElement('style');
style.id = 'gis-search-style';
style.textContent = `
.gis-search-floating{position:absolute;z-index:650;top:14px;left:14px;width:min(420px,calc(100% - 28px));font-family:inherit}
.gis-search-field{display:flex;align-items:center;gap:8px;background:#fff;border:1px solid #d6e3dc;border-radius:16px;box-shadow:0 10px 28px rgba(15,23,42,.12);padding:10px 12px}
.gis-search-field i{color:#0a8f4d}.gis-search-field input{border:0;outline:0;width:100%;font-size:15px;background:transparent;color:#172033}
.gis-search-clear{border:0;background:#eef7f2;color:#0a6f3d;border-radius:999px;width:28px;height:28px;display:grid;place-items:center}
.gis-search-results{margin-top:8px;background:#fff;border:1px solid #d6e3dc;border-radius:14px;box-shadow:0 16px 40px rgba(15,23,42,.16);overflow:hidden;max-height:360px;overflow-y:auto}
.gis-search-item{display:grid;grid-template-columns:auto 1fr;gap:2px 10px;width:100%;border:0;background:#fff;text-align:left;padding:11px 13px;border-bottom:1px solid #eef2f7;color:#172033}
.gis-search-item:hover,.gis-search-item:focus{background:#eefaf3;outline:0}.gis-search-code{font-weight:800;color:#075f36}.gis-search-name{font-weight:700;color:#172033}.gis-search-meta{grid-column:1/3;color:#64748b;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.gis-search-warning{grid-column:1/3;color:#b45309;font-size:12px;font-weight:700}.gis-search-empty{padding:12px 14px;color:#64748b;font-size:14px}.gis-search-blink{animation:gisSearchBlink .6s ease-in-out 5}@keyframes gisSearchBlink{0%,100%{filter:none;transform:scale(1)}50%{filter:drop-shadow(0 0 12px #ef4444);transform:scale(1.18)}}
@media (max-width:767px){.gis-search-floating{top:10px;left:10px;width:calc(100% - 20px)}.gis-search-field{border-radius:14px;padding:9px 10px}.gis-search-field input{font-size:14px}.gis-search-results{max-height:300px}}
`;
document.head.appendChild(style);
}
function mount() {
const mapEl = document.getElementById('gisMap');
if (!mapEl || document.getElementById('gisHouseholdSearch')) return;
const parent = mapEl.parentElement;
if (!parent) return;
if (getComputedStyle(parent).position === 'static') parent.style.position = 'relative';
ensureStyles();
const box = document.createElement('div');
box.className = 'gis-search-floating';
box.id = 'gisHouseholdSearch';
box.innerHTML = `
<div class="gis-search-field">
<i class="fas fa-search" aria-hidden="true"></i>
<input type="search" autocomplete="off" placeholder="Tìm mã hộ, chủ hộ, nhân khẩu..." aria-label="Tìm hộ trên bản đồ">
<button type="button" class="gis-search-clear" title="Xóa tìm kiếm" aria-label="Xóa tìm kiếm" hidden>&times;</button>
</div>
<div class="gis-search-results" hidden></div>
`;
parent.appendChild(box);
const input = qs('input', box);
const clear = qs('.gis-search-clear', box);
const list = qs('.gis-search-results', box);
input.addEventListener('input', () => {
const value = input.value.trim();
clear.hidden = value.length === 0;
window.clearTimeout(state.timer);
if (value.length < 2) {
list.hidden = true;
list.innerHTML = '';
return;
}
state.timer = window.setTimeout(async () => {
try {
renderResults(box, await search(value));
} catch (error) {
console.error('[GIS Search]', error);
showToast(error.message || 'Không tìm kiếm được GIS', 'error');
}
}, 280);
});
clear.addEventListener('click', () => {
input.value = '';
clear.hidden = true;
list.hidden = true;
input.focus();
});
list.addEventListener('click', (event) => {
const button = event.target.closest('.gis-search-item');
if (!button) return;
const item = state.results[Number(button.dataset.index)];
if (!item) return;
list.hidden = true;
input.value = `${item.household_code} - ${item.head_name || ''}`.trim();
focusHousehold(item);
});
document.addEventListener('click', (event) => {
if (!box.contains(event.target)) list.hidden = true;
});
}
function boot() {
mount();
document.addEventListener('thon09:screen-change', mount);
}
if (document.readyState === 'loading') {
document.addEventListener('DOMContentLoaded', boot);
} else {
boot();
}
})();
